class BlockDecomposition {
private:
	// --------------------------------------
	// [通用] 变量
	// --------------------------------------
	int n;                  // 数组总长度
	int block_size;         // 块的大小 S
	int num_blocks;         // 块的总数
	vector<int> id;         // id[i] 表示原数组第 i 个元素属于哪个块
	vector<int> L, R;       // L[b], R[b] 分别表示第 b 个块的左右端点下标

	int get_block_id(int pos) {
		// 获取原数组第 pos 个元素属于哪个块
		return (pos - 1) / block_size + 1;
	}
	int get_diff_id(int pos) {
		// 获取原数组第 pos 个元素的块内下标
		return (pos - 1) % block_size;
	}

	// --------------------------------------
	// [具体情况具体分析] 块内维护的附加信息与标记
	// --------------------------------------
	vector<deque<int>> lzq;   // 每个块维护的双端队列
	vector<vector<int>> cnt;  // 每个块维护的计数数组，范围：[1, N]

public:
	// --------------------------------------
	// [通用] 构造函数，初始化
	// --------------------------------------
	BlockDecomposition(const vector<int>& input) {
		n = input.size() - 1;
		block_size = max(1, (int)sqrt(n));
		num_blocks = (n - 1) / block_size + 1;

		id.resize(n + 1);
		L.resize(num_blocks + 1, 0);
		R.resize(num_blocks + 1, 0);

		// [具体情况具体分析] 对具体分析的变量初始化空间
		lzq.resize(num_blocks + 1);
		cnt = Vec2<int>(num_blocks + 1, n + 1, 0);

		// 计算每个元素的块归属 和 每个块的左右边界
		fa(i, 1, n) {
			id[i] = (i - 1) / block_size + 1;
			if (L[id[i]] == 0)L[id[i]] = i;
			R[id[i]] = i;

			// 初始化队列和计数数组
			lzq[id[i]].pb(input[i]);
			cnt[id[i]][input[i]]++;
		}
	}

	// --------------------------------------
	// [具体情况具体分析] 区间修改操作，怎么修改具体情况具体分析
	// 逻辑骨架是通用的：分同块、左散块、右散块、中间整块
	// --------------------------------------
	void update(int l, int r) {
		if (l == r)return;

		int bl = id[l], br = id[r];
		int idxl = get_diff_id(l), idxr = get_diff_id(r);

		// 把 r 位置的元素从 br 块中取出来
		int val = lzq[br][idxr];
		lzq[br].erase(lzq[br].begin() + idxr);
		cnt[br][val]--;

		// 把 l 位置的元素加到 bl 块中
		lzq[bl].insert(lzq[bl].begin() + idxl, val);
		cnt[bl][val]++;

		// 中间的进行移位
		fa(b, bl + 1, br) {
			cnt[b - 1][lzq[b - 1].back()]--;
			cnt[b][lzq[b - 1].back()]++;
			lzq[b].push_front(lzq[b - 1].back());
			lzq[b - 1].pop_back();
		}
	}

	// --------------------------------------
	// [具体情况具体分析] 区间查询操作，怎么查询具体情况具体分析
	// 逻辑骨架是通用的：分同块、左散块、右散块、中间整块
	// --------------------------------------
	int query(int l, int r, int x) {
		int bl = id[l], br = id[r];
		int res = 0;
		if (bl == br) {
			// 在同一个块内，暴力判断
			// 直接把块队列取出来，看看下标是否符合条件即可
			var tmp = lzq[bl];
			int now = L[bl];
			while (tmp.size()) {
				if (now >= l and now <= r and tmp.front() == x)res++;
				now++;
				tmp.pop_front();
			}
		}
		else {
			// 左散块暴力
			// 直接把块队列取出来，看看下标是否符合条件即可
			var tmp = lzq[bl];
			int now = L[bl];
			while (tmp.size()) {
				if (now >= l and now <= r and tmp.front() == x)res++;
				now++;
				tmp.pop_front();
			}

			// 右散块暴力
			// 直接把块队列取出来，看看下标是否符合条件即可
			tmp = lzq[br];
			now = L[br];
			while (tmp.size()) {
				if (now >= l and now <= r and tmp.front() == x)res++;
				now++;
				tmp.pop_front();
			}

			// 中间整块，利用预处理的计数数组计算
			fa(b, bl + 1, br - 1)res += cnt[b][x];
		}
		return res;
	}
};


void solve(int CASE)
{
	int n; cin >> n;
	var a = vector<int>(n + 1);
	fa(i, 1, n)cin >> a[i];
	var bd = BlockDecomposition(a);
	int q; cin >> q;
	int ans = 0;
	while (q--) {
		int op, l, r; cin >> op >> l >> r;
		if (op == 1) {
			l = (l + ans - 1) % n + 1;
			r = (r + ans - 1) % n + 1;
			if (l > r)swap(l, r);
			bd.update(l, r);
		}
		else {
			int x; cin >> x;
			l = (l + ans - 1) % n + 1;
			r = (r + ans - 1) % n + 1;
			x = (x + ans - 1) % n + 1;
			if (l > r)swap(l, r);
			ans = bd.query(l, r, x);
			cout << ans << endl;
		}
	}
	return;
}
